import os
import json
import glob
from pathlib import Path

workspace_path = "/tmp_workspace"
episodes_path = os.path.join(workspace_path, "episodes")
evidence_path = os.path.join(workspace_path, "evidence")
results_path = os.path.join(workspace_path, "results")

# Check what exists
print("Workspace contents:")
print(os.listdir(workspace_path) if os.path.exists(workspace_path) else "Does not exist")

print("\nEpisodes contents:")
if os.path.exists(episodes_path):
    for item in sorted(os.listdir(episodes_path)):
        full_path = os.path.join(episodes_path, item)
        if os.path.isfile(full_path):
            print(f"  File: {item}")
        else:
            print(f"  Dir: {item}")
            for subitem in sorted(os.listdir(full_path)):
                print(f"    {subitem}")
else:
    print("Does not exist")

print("\nEvidence contents:")
if os.path.exists(evidence_path):
    for item in sorted(os.listdir(evidence_path)):
        full_path = os.path.join(evidence_path, item)
        if os.path.isfile(full_path):
            print(f"  File: {item}")
        else:
            print(f"  Dir: {item}")
            for subitem in sorted(os.listdir(full_path)):
                print(f"    {subitem}")
else:
    print("Does not exist")

print("\nResults contents:")
if os.path.exists(results_path):
    print(os.listdir(results_path))
else:
    print("Does not exist")
